    def air_compressor_pwmeter():
        # air_compressor_pwmeter_thread-PW meter 4 : voltage = 120.16 V, current = 0.00 A
        fname = 'air_compressor_pwmeter'
        head = ['timestamp','voltage','current']
        writers = {}
        finished = False

        def process_log(ts, src, msg):
            if not msg.startswith('air_compressor_pwmeter_thread-PW meter'):
                return False
            if finished:
                return True

            vv = msg.split("=")
            if len(vv) != 3:
                # pass
                return True
            vv = [v.strip().split(" ")[0] for v in vv[1:]]
            vv.insert(0, timestamp_str(ts))

            if src not in writers:
                writers[src] = get_writer(pathpre, fname, src)
                writers[src].write(",".join(head)+"\n")

            writers[src].write(",".join(vv)+"\n")
            return True

        def process_result():
            res = {}
            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            nonlocal finished
            finished = True
            return res

        return process_log, process_result

    process_rules.append(air_compressor_pwmeter())


