    def log_tag_value():
        fname = 'log_tag_value'
        heads = {}
        writers = {}
        run_again = False
        skip_values = False
        tried_run_again = False

        def write_head(name):
            writers[name] = get_writer(pathpre, fname, name)
            writers[name].write(f'timestamp,{",".join(heads[name])}\n')

        def process_log(ts, src, msg):
            nonlocal run_again, skip_values
            if msg.startswith("log_tag_info-"):
                jo = json.loads(msg[13:])
                if jo["name"] not in heads:
                    heads[jo["name"]] = jo["tags"]
                if not skip_values and jo["name"] not in writers:
                    write_head(jo["name"])
                return True
            elif msg.startswith('{ "log_type":"tag_info"'):
                jo = json.loads(msg)
                if jo["name"] not in heads:
                    heads[jo["name"]] = jo["tags"]
                if not skip_values and jo["name"] not in writers:
                    write_head(jo["name"])
                return True
            elif msg.startswith("log_tag_value-") or msg.startswith('{ "log_type":"tag_value"'):
                if skip_values:
                    return True

                PTN1 = '"name":"'
                PTN2 = '", "values":['
                if (f1 := msg.find(PTN1)) != -1 and (f2 := msg.find(PTN2)) != -1 and (f3 := msg.find("]", f2)) != -1:
                    name = msg[f1+len(PTN1):f2]
                    if name not in heads:
                        print(f"Can't find schema for:{name}, need run again...")
                        if tried_run_again:
                            raise SchemaErrorException()
                        run_again = True
                        skip_values = True
                        return True
                    # assert name in writers, f"{(ts, msg)}"

                    if name not in writers:
                        write_head(name)

                    vals = msg[f2+len(PTN2):f3].split(",")
                    # assert len(vals) == len(head[name]), f"{(ts, msg)}"
                    vals.insert(0, timestamp_str(ts))  # Add timestamp at the beginning
                    writers[name].write(",".join(vals)+"\n")
                    return True
            return False

        def process_result():
            nonlocal writers, run_again, skip_values, tried_run_again
            res = {}

            if run_again:
                for writer in writers.values():
                    writer.close()
                writers = {}
                run_again = False
                skip_values = False
                tried_run_again = True
                res["__log_tag_value_run_again__"] = []
                return res

            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            return res

        process_log.is_log_tag_value = True
        return process_log, process_result

