    def ev_handler():
        fname = 'ev_handler'
        head = []
        writers = {}
        finished = False

        def process_log(ts, src, msg):
            if not msg.startswith('_ev_handler: {"servo":['):
                return False
            if finished:
                return True

            jo = json.loads(msg[13:])
            # pprint(jo)

            collect_tags = True if not head else False
            vals = [timestamp_str(ts)]

            if collect_tags:
                head.append('timestamp')

            for i, servo in enumerate(jo["servo"]):
                if collect_tags:
                    head.append(f"servo_{i+1}_st")
                    head.append(f"servo_{i+1}_alarm")
                    head.append(f"servo_{i+1}_current")
                    head.append(f"servo_{i+1}_speed")
                    head.append(f"servo_{i+1}_voltage")
                    head.append(f"servo_{i+1}_ai_in")
                    head.append(f"servo_{i+1}_hour")
                vals.extend([
                    str(servo["st"]),
                    str(servo["alarm"]),
                    str(servo["current"]),
                    str(servo["speed"]),
                    str(servo["voltage"]),
                    str(servo["ai_in"]),
                    str(servo["hour"])
                ])

            for i, cy_ctl in enumerate(jo["fpga"]['cy_ctl']):
                if collect_tags:
                    head.append(f"fpga_cy_ctl_{i+1}_en")
                    head.append(f"fpga_cy_ctl_{i+1}_si")
                    head.append(f"fpga_cy_ctl_{i+1}_so")
                vals.extend([
                    str(cy_ctl["en"]),
                    str(cy_ctl["si"]),
                    str(cy_ctl["so"]),
                ])

            for i, tag in enumerate(jo["plc"]):
                if collect_tags:
                    head.append(tag["tag_name"])
                vals.append("".join(str(v) for v in tag["tag_val"]))

            assert len(vals) == len(head)

            if src not in writers:
                writers[src] = get_writer(pathpre, fname, src)
                writers[src].write(",".join(head)+"\n")

            writers[src].write(",".join(vals)+"\n")
            return True

        def process_result():
            res = {}
            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            nonlocal finished
            finished = True
            return res

        return process_log, process_result

    process_rules.append(ev_handler())



