    # 1579088973815526|0|1|DI_PW_EMS_STATUS=1,DI_PW_POWER_ABNORMAL=2,DI_OP_MODE_1=4,DI_OP_MODE_2=3,DI_RESET=5,DI_STOP=6,DI_PLAY=7,DI_PN1_READY=8,DI_PN2_READY=9,DI_PN3_READY=10,DI_WHEELCHAIR=11,DI_EARTHQUAKE=12,DI_FIRE_ALARM=13,DI_1F_A_DR_CLOSED=14,DI_1F_B_DR_CLOSED=15,DI_2F_A_DR_CLOSED=16,DI_2F_B_DR_CLOSED=17,DI_3F_A_DR_CLOSED=18,DI_3F_B_DR_CLOSED=19,DI_PN0_EMS_BTN_STATUS=20,DI_PN1_EMS_BTN_STATUS=21,DI_PN2_EMS_BTN_STATUS=22,DI_PN3_EMS_BTN_STATUS=23,DI_PW_EMS_BTN_STATUS=24,DO_HEART_BEAT=25,DO_PN0_PLAY_LED=26,DO_PN1_READY_LED=27,DO_PN1_INSHOW_LED=28,DO_PN2_READY_LED=29,DO_PN2_INSHOW_LED=30,DO_PN3_READY_LED=31,DO_PN3_INSHOW_LED=32,DO_1F_A_DR_OPEN=33,DO_1F_B_DR_OPEN=34,DO_2F_A_DR_OPEN=35,DO_2F_B_DR_OPEN=36,DO_3F_A_DR_OPEN=37,DO_3F_B_DR_OPEN=38,DO_ESTOP=39,
    def di_handler():
        fname = 'di'
        head = {}
        writers = {}
        finished = False

        re1 = re.compile(r'^([A-Z0-9_():]+)\=(\d+)\,')
        re2 = re.compile(r'^[\d,]+$')

        def process_log(ts, src, msg):
            if src in head:
                if finished:
                    return True

                if not re.match(re2, msg):
                    return False
                vv = [timestamp_str(ts)]
                values = msg.split(",")
                for _, idx in head[src]:
                    vv.append(values[idx-1])

                writers[src].write(",".join(vv)+"\n")
                return True

            elif msg.startswith(('DI_')):
                if finished:
                    return True

                schema = []
                end = 0
                while m2 := re1.match(msg[end:]):
                    schema.append((m2[1], int(m2[2])))
                    end += m2.end()

                if len(schema) == 0:
                    return False

                assert src not in head
                head[src] = schema
                if src not in writers:
                    writers[src] = get_writer(pathpre, fname, src)
                    hh = [name for name, _ in head[src]]
                    writers[src].write(f'timestamp,{",".join(hh)}\n')

                return True

            else:
                return False

        def process_result():
            res = {}
            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            nonlocal finished
            finished = True
            return res

        return process_log, process_result

    process_rules.append(di_handler())



