    # 1752543784494818|15|0|0|0|DO 0 : 0,DO 1 : 0,DO 2 : 0,DO 3 : 0,DO 4 : 0,DO 5 : 0,DO 6 : 0,DO 7 : 0,DO 8 : 0,DO 9 : 0,DO 10 : 0,DO 11 : 0,DO 12 : 0,DO 13 : 0,DO 14 : 0,DO 15 : 0,
    # 1752543784534818|15|1|0|0|DO 0 : 0,DO 1 : 0,DO 2 : 0,DO 3 : 0,DO 4 : 0,DO 5 : 0,DO 6 : 0,DO 7 : 0,DO 8 : 0,DO 9 : 0,DO 10 : 0,DO 11 : 0,DO 12 : 0,DO 13 : 0,DO 14 : 0,DO 15 : 0,
    def ssm_trex_a():
        fname = 'do'
        head = {}
        writers = {}
        finished = False

        re2 = re.compile(r'^DO 0 : (\d+),DO 1 : (\d+),DO 2 : (\d+),DO 3 : (\d+),DO 4 : (\d+),DO 5 : (\d+),DO 6 : (\d+),DO 7 : (\d+),DO 8 : (\d+),DO 9 : (\d+),DO 10 : (\d+),DO 11 : (\d+),DO 12 : (\d+),DO 13 : (\d+),DO 14 : (\d+),DO 15 : (\d+),$')

        def process_log(ts, src, msg):
            if not msg.startswith('DO '):
                return False

            if not (m := re2.match(msg)):
                return False # Not a match for re2, so return False

            if finished:
                return True

            if src not in head:
                head[src] = ["timestamp"]
                for i in range(16):
                    head[src].append(f"DO_{i}")

            vals = [timestamp_str(ts)]
            vals.extend(m.group(i+1) for i in range(16))

            assert len(head[src]) == len(vals), f"Header length {len(head[src])} != Values length {len(vals)} for src {src}. Message: {msg}"

            if src not in writers:
                writers[src] = get_writer(pathpre, fname, src)
                writers[src].write(",".join(head[src])+"\n")

            writers[src].write(",".join(vals)+"\n")
            return True

        def process_result():
            res = {}
            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            nonlocal finished
            finished = True
            return res

        return process_log, process_result

    process_rules.append(ssm_trex_a())



