    # ssm-odyssey
    # 1754011589708948|1003|0|0|0|DI=0000,DO=0000
    def ssm_trex_b():
        fname = 'dio'
        head = {}
        writers = {}
        finished = False

        re2 = re.compile(r'^DI=([0-9A-F]+),DO=([0-9A-F]+)$')

        def process_log(ts, src, msg):
            if not msg.startswith('DI='):
                return False

            if not (m := re2.match(msg)):
                raise ValueError(msg)

            if finished:
                return True

            if src not in head:
                head[src] = ["timestamp"]
                head[src].extend(f"DI{i+1}" for i in range(len(m[1])*4))
                head[src].extend(f"DO{i+1}" for i in range(len(m[2])*4))

            vals = [timestamp_str(ts)]
            for k in range(2):
                v = int(hex_to_signed_int_str(m[k+1]))
                for i in range(len(m[k+1])*4):
                    vals.append('1' if v & (0x01<<i) else '0')

            # print(m[1], m[2], vals)

            assert len(head[src]) == len(vals), f"Header length {len(head[src])} != Values length {len(vals)} for src {src}. Message: {msg}"

            if src not in writers:
                writers[src] = get_writer(pathpre, fname, src)
                writers[src].write(",".join(head[src])+"\n")
            writers[src].write(",".join(vals)+"\n")
            return True

        def process_result():
            res = {}
            for src, writer in writers.items():
                if not (rr := writer.close()):
                    continue

                res[rr[0]] = rr[1]
            nonlocal finished
            finished = True
            return res

        return process_log, process_result

