            # ==========  use json_to_map
            for kk in ['warn_data', 'alarm_data']:
                if kk in jo:
                    ads = ""
                    for ad in jo[kk]:
                        m_str = ad['m'].replace('"',"").replace("'","").replace(",",".")
                        ads += f"(i:{ad['i']} o:{ad['o']} s:{ad['s']} m:{m_str})"
                    jo[kk] = f'"{ads}"'

            jm = json_to_map(jo)

            # print(jm.keys())

