def _process_line(check_num, line):
    if check_num == 4:
        parts = line.split("|", 3)
        if len(parts) == 4:
            return parts[0], parts[1], parts[3].replace("\n", "").rstrip()
    elif check_num == 6:
        parts = line.split("|", 5)
        if len(parts) == 6:
            return parts[0], parts[1], parts[5].replace("\n", "").rstrip()

def log_item_from_txt(fpath):
    fsize_ttl = os.path.getsize(fpath)
    check_num = 0
    last = None
    with open(fpath, "r", encoding="utf-8", errors='replace') as f:
        fsize = 0
        for line in f:
            if len(line) == 0 or not line[0].isdigit():
                last += line
                continue
            if last is None:
                last = line
                continue

            if check_num == 0:
                check_num = last[:50].count("|") + 1
            fsize += (len(last) + 1)
            yield fsize/fsize_ttl, _process_line(check_num, last)
            last = line
        fsize += (len(last) + 1)
        yield fsize/fsize_ttl, _process_line(check_num, last)


def log_item_from_xz(fpath):
    check_num = 0
    last = None
    with lzma.open(fpath, "r") as f:
        f.seek(0, os.SEEK_END)
        fsize_ttl = f.tell()
        f.seek(0, os.SEEK_SET)
        fsize = 0
        while (line := f.readline()):
            line = line.decode("utf-8", errors='replace')
            if len(line) == 0 or not line[0].isdigit():
                last += line
                continue
            if last is None:
                last = line
                continue

            if check_num == 0:
                check_num = last.count("|") + 1
            fsize += (len(last) + 1)
            yield fsize/fsize_ttl, _process_line(check_num, last)
            last = line
        fsize += (len(last) + 1)
        yield fsize/fsize_ttl, _process_line(check_num, last)

def log_item_from_zstd(fpath):
    check_num = 0
    last = None
    with open(fpath, "rb") as f:
        dctx = zstd.ZstdDecompressor()
        with dctx.stream_reader(f) as reader:
            text_stream = io.TextIOWrapper(reader, encoding='utf-8', errors='replace')

            f.seek(0, os.SEEK_END)
            fsize_ttl = f.tell()
            f.seek(0, os.SEEK_SET)
            fsize = 0

            while (line := text_stream.readline()):
                if len(line) == 0 or not line[0].isdigit():
                    if last is not None:
                        last += line
                    else:
                        last = line
                    continue
                if last is None:
                    last = line
                    continue

                if check_num == 0:
                    check_num = last.count("|") + 1
                yield (f.tell() / fsize_ttl) if fsize_ttl > 0 else 0.0, _process_line(check_num, last)
                last = line

            if last is not None:
                yield (f.tell() / fsize_ttl) if fsize_ttl > 0 else 0.0, _process_line(check_num, last)

def log_item_from_csv(fpath):
    df = pd.read_csv(fpath, low_memory=False, keep_default_na=True, engine="c")
    rows = len(df)

    for row in df.itertuples():
        yield row.Index/rows, (row.ts, row.src, row.msg)


def log_item_from_string(text: str):
    check_num = 0
    last = None
    for line in text.splitlines():
        if len(line) == 0 or not line[0].isdigit():
            last += line
            continue
        if last is None:
            last = line
            continue

        if check_num == 0:
            check_num = last[:50].count("|") + 1
        yield 0, _process_line(check_num, last)
        last = line
    yield 0, _process_line(check_num, last)


def log_item_from_db(fpath):
    try:
        # fname = f"file:///{ fpath }?mode=ro"
        # with sqlite3.connect(fname, uri=True, check_same_thread=False) as conn:
        with sqlite3.connect(fpath, uri=True, check_same_thread=False) as conn:
            conn.text_factory = lambda b: b.decode(errors='replace')
            # try:
            #     conn.execute("PRAGMA journal_mode=MEMORY;")
            # except sqlite3.DatabaseError as e:
            #     print("Warning:", e)

            raw_ttl = 0
            try:
                raw_ttl = conn.execute("SELECT COUNT(*) FROM log_raw;").fetchone()[0]
            except sqlite3.DatabaseError as e:
                print("Warning:", e)

            raw_cnt = 0
            for row in conn.execute("SELECT * FROM log_raw;"):
                raw_cnt += 1
                if len(row) == 4:
                    yield 0 if raw_ttl == 0 else raw_cnt/raw_ttl, (row[0], row[1], row[3].replace("\n", ""))
                elif len(row) == 6:
                    yield 0 if raw_ttl == 0 else raw_cnt/raw_ttl, (row[0], row[1], row[5].replace("\n", ""))
                else:
                    raise sqlite3.DatabaseError()

    except sqlite3.DatabaseError as e:
        print(e)








def process_test(text):
    process_rules = prepare_process_rules("")

    for progress, rec in log_item_from_string(text):
        ts, src, msg = rec
        for process_log, _ in process_rules:
            if process_log(ts, src, msg):
                break
        # if not processed and len(msg) > 0:
        #     print(ts, src, msg)

    allres = {}
    run_again_log_tag_value = False
    for _, process_result in process_rules:
        res = process_result()
        if res:
            if "__log_tag_value_run_again__" in res:
                run_again_log_tag_value = True
                del res["__log_tag_value_run_again__"]
            allres.update(res)

    if run_again_log_tag_value:
        for progress, rec in log_item_from_string(text):
            ts, src, msg = rec
            for process_log, _ in process_rules:
                if getattr(process_log, "is_log_tag_value", False) and process_log(ts, src, msg):
                    break
        for process_log, process_result in process_rules:
            if not getattr(process_log, "is_log_tag_value", False):
                continue
            res = process_result()
            if res:
                allres.update(res)

    return allres

