def show_window(files: list):
    import sys
    from PySide6.QtWidgets import (QApplication, QWidget, QVBoxLayout, QPushButton,
                                QListView, QFileDialog, QAbstractItemView, QTextEdit, QProgressBar,
                                QMenu, QMessageBox, QDialog, QLabel, QDialogButtonBox) # 導入 QMessageBox
    from PySide6.QtCore import QObject, QThread, Signal, Slot, QStringListModel, Qt, QUrl
    import threading

    class Worker(QObject):
        # 定義信號：一個用於回報進度，一個用於通知完成
        progress = Signal(str)
        finished = Signal(str)
        request_schema = Signal(str)  # signal to request schema from user (carries error message)

        def __init__(self, parent=None):
            super().__init__(parent)
            self._interrupt = False
            self._schema_event = threading.Event()
            self._schema_text = None  # will be set by the main thread

        def interrupt(self):
            self.progress.emit(f"Interrupted")
            self._interrupt = True

        # 建立一個槽，用來接收從主線程傳來的啟動指令和參數
        @Slot(str)
        def process_file(self, file_path: str):
            self._interrupt = False

            filepath = os.path.abspath(file_path)
            pathpre, ext = os.path.splitext(filepath)

            start_t = time.time()
            tick_t = start_t

            index = 0

            if ext == ".db":
                log_item_generator = log_item_from_db
            elif ext == ".txt":
                log_item_generator = log_item_from_txt
            elif ext == ".xz":
                log_item_generator = log_item_from_xz
            elif ext in [".zst", ".zstd"]:
                log_item_generator = log_item_from_zstd
            elif ext == ".csv":
                log_item_generator = log_item_from_csv

            process_rules = prepare_process_rules(pathpre)

            def process_with_schema_ui(ts, src, msg, only_log_tag_value=False):
                try:
                    for process_log, _ in process_rules:
                        if only_log_tag_value and not getattr(process_log, "is_log_tag_value", False):
                            continue
                        if process_log(ts, src, msg):
                            return True

                except SchemaErrorException as e:
                    # show a dialog window for user paste schema, and process_log line by line
                    self._schema_event.clear()
                    self._schema_text = None
                    self.request_schema.emit(str(e))
                    self._schema_event.wait()  # block until user responds

                    if self._schema_text:
                        # reprocess the log line with user-provided schema
                        for schema_line in self._schema_text.splitlines():
                            schema_line = schema_line.strip()
                            if not schema_line:
                                continue
                            try:
                                for process_log_fn, _ in process_rules:
                                    if only_log_tag_value and not getattr(process_log_fn, "is_log_tag_value", False):
                                        continue
                                    if process_log_fn(ts, src, schema_line):
                                        # print("schema")
                                        break
                            except SchemaErrorException:
                                pass
                        # now retry the original line
                        try:
                            for process_log_fn, _ in process_rules:
                                if only_log_tag_value and not getattr(process_log_fn, "is_log_tag_value", False):
                                    continue
                                if process_log_fn(ts, src, msg):
                                    # print("Fix msg")
                                    break
                        except SchemaErrorException:
                            self.progress.emit(f"Schema error persists: {e}")
                    else:
                        self.finished.emit(f"Schema input cancelled, skip this file.")
                        return False

                except Exception as e:
                    print((ts, src, msg))
                    # re throw
                    raise e

                return True

            # run_again = False
            # while True:
            for progress, rec in log_item_generator(filepath):
                # print(self._interrupt)
                if index % 1000 == 0:
                    if self._interrupt:
                        return

                    if ((now_t := time.time()) - tick_t) > 0.1:
                        self.progress.emit(f"Processing: {progress*100:.0f}% {index}")
                        tick_t = now_t

                index += 1

                if rec is None:
                    continue
                ts, src, msg = rec

                # print(msg, msg.rstrip())
                # msg = msg.replace("\n", "").rstrip()
                # processed = False
                if not process_with_schema_ui(ts, src, msg):
                    return

                # if not processed and len(msg) > 0:
                #     print(ts, src, msg)

            # print(f"\rProcessing: {progress*100:.0f}% {index}")

            run_again_log_tag_value = False
            for process_log, process_result in process_rules:
                if res := process_result():
                    if "__log_tag_value_run_again__" in res:
                        run_again_log_tag_value = True
                        del res["__log_tag_value_run_again__"]

                    for fname, lines in res.items():
                        if self._interrupt:
                            return

                        fn = f"{pathpre}{fname}"
                        self.progress.emit(f"Processing: {fn}")
                        with open(fn, "w", encoding="utf-8") as f:
                            f.writelines(lines)

            if run_again_log_tag_value:
                self.progress.emit(f"Processing log_tag_value again")
                index = 0

                for progress, rec in log_item_generator(filepath):
                    if index % 1000 == 0:
                        if self._interrupt:
                            return

                        if ((now_t := time.time()) - tick_t) > 0.1:
                            self.progress.emit(f"Processing log_tag_value again: {progress*100:.0f}% {index}")
                            tick_t = now_t

                    index += 1

                    if rec is None:
                        continue
                    ts, src, msg = rec

                    if not process_with_schema_ui(ts, src, msg, only_log_tag_value=True):
                        return

                for process_log, process_result in process_rules:
                    if not getattr(process_log, "is_log_tag_value", False):
                        continue

                    if res := process_result():
                        if "__log_tag_value_run_again__" in res:
                            del res["__log_tag_value_run_again__"]

                        for fname, lines in res.items():
                            if self._interrupt:
                                return

                            fn = f"{pathpre}{fname}"
                            self.progress.emit(f"Processing: {fn}")
                            with open(fn, "w", encoding="utf-8") as f:
                                f.writelines(lines)



            # 任務完成，發送完成信號並附帶結果
            result = f"檔案 '{file_path}' 已成功處理完畢！  {time.time() - start_t}s"
            self.finished.emit(result)



    class FileSelectionApp(QWidget):
        sig_process_file = Signal(str)
        # sig_interrupt = Signal(str)

        def __init__(self):
            super().__init__()
            self.setWindowTitle("檔案選擇應用程式")
            self.setGeometry(100, 100, 600, 600)

            self.file_list_model = QStringListModel()
            self.selected_files = []

            self.init_thread()
            self.init_ui()
            self.setAcceptDrops(True) # 啟用拖放功能

        def init_thread(self):
            self.thread = QThread()
            self.worker = Worker()
            self.worker.moveToThread(self.thread)

            self.sig_process_file.connect(self.worker.process_file)
            # self.sig_interrupt.connect(self.worker.stop)
            self.worker.progress.connect(self.progress_message)
            self.worker.finished.connect(self.task_finished)
            self.worker.request_schema.connect(self.show_schema_dialog)

            # self.thread.finished.connect(self.thread.deleteLater)
            # self.worker.finished.connect(self.thread.quit)
            # self.worker.finished.connect(self.worker.deleteLater)
            self.thread.start()

        def init_ui(self):
            layout = QVBoxLayout()

            # 選擇檔案按鈕
            self.select_button = QPushButton("選擇檔案")
            self.select_button.clicked.connect(self.open_file_dialog)
            layout.addWidget(self.select_button)

            # 檔案列表視圖
            self.list_view = QListView()
            self.list_view.setModel(self.file_list_model)
            self.list_view.setSelectionMode(QAbstractItemView.ExtendedSelection) # 允許多選
            self.list_view.setContextMenuPolicy(Qt.CustomContextMenu) # 啟用自訂右鍵選單
            self.list_view.customContextMenuRequested.connect(self.show_context_menu) # 連接右鍵選單事件
            layout.addWidget(self.list_view)

            # 執行按鈕
            self.run_button = QPushButton("執行")
            self.run_button.clicked.connect(self.run_process)
            layout.addWidget(self.run_button)
            self.stop_button = QPushButton("中斷")
            self.stop_button.clicked.connect(self.stop_process)
            layout.addWidget(self.stop_button)

            # 訊息顯示區
            self.message_area = QTextEdit()
            self.message_area.setReadOnly(True) # 設為唯讀
            layout.addWidget(self.message_area)

            # progress bar
            self.progress_bar = QProgressBar()
            self.progress_bar.setRange(0, 100)
            self.progress_bar.setValue(0)
            layout.addWidget(self.progress_bar)

            self.setLayout(layout)

        def open_file_dialog(self):
            filenames, _ = QFileDialog.getOpenFileNames(self, "選擇檔案", "", "所有檔案 (*.*)")
            if filenames:
                for file in filenames:
                    if file not in self.selected_files:
                        self.selected_files.append(file)
                self.update_file_list_view()
                self.append_message(f"已選擇 {len(filenames)} 個檔案。")

        def update_file_list_view(self):
            self.selected_files.sort()
            self.file_list_model.setStringList(self.selected_files)

        def run_process(self):
            if len(self.selected_files) == 0:
                return

            ff = self.selected_files.pop(0)
            self.append_message(f"開始處理檔案：{ff}...")
            self.sig_process_file.emit(ff)
            self.update_file_list_view()

        def stop_process(self):
            self.worker.interrupt()

        def task_finished(self, result: str):
            self.append_message(result)
            self.progress_bar.setFormat("")
            self.run_process()

        def progress_message(self, message: str):
            self.progress_bar.setFormat(message)

        def append_message(self, message: str):
            self.message_area.append(message) # 在 Text Area 中添加訊息

        # --- 右鍵選單相關功能 ---
        def show_context_menu(self, pos):
            """顯示列表視圖的右鍵選單"""
            menu = QMenu(self)
            remove_action = menu.addAction("從列表中移除")
            clear_all_action = menu.addAction("清空所有檔案")

            action = menu.exec(self.list_view.mapToGlobal(pos))

            if action == remove_action:
                self.remove_selected_files()
            elif action == clear_all_action:
                self.clear_all_files()

        def remove_selected_files(self):
            """移除列表中選定的檔案"""
            selected_indexes = self.list_view.selectedIndexes()
            if not selected_indexes:
                self.append_message("請先選擇要移除的檔案。")
                return

            # 獲取選定的檔案路徑
            files_to_remove = []
            for index in selected_indexes:
                files_to_remove.append(self.file_list_model.data(index, Qt.DisplayRole))

            # 從 self.selected_files 中移除這些檔案
            for file in files_to_remove:
                if file in self.selected_files:
                    self.selected_files.remove(file)

            self.update_file_list_view()
            self.append_message(f"已從列表中移除 {len(files_to_remove)} 個檔案。")

        def clear_all_files(self):
            """清空所有檔案"""
            if not self.selected_files:
                self.append_message("列表中沒有檔案可清空。")
                return

            reply = QMessageBox.question(self, "確認清空", "您確定要清空所有檔案嗎？",
                                        QMessageBox.Yes | QMessageBox.No, QMessageBox.No)
            if reply == QMessageBox.Yes:
                self.selected_files.clear()
                self.update_file_list_view()
                self.append_message("已清空所有檔案。")
            else:
                self.append_message("取消清空操作。")


        # 拖放事件處理
        def dragEnterEvent(self, event):
            if event.mimeData().hasUrls():
                event.acceptProposedAction()
            else:
                event.ignore()

        def dropEvent(self, event):
            if event.mimeData().hasUrls():
                for url in event.mimeData().urls():
                    if url.isLocalFile() and (filepath := url.toLocalFile()) not in self.selected_files:
                        self.selected_files.append(filepath)
                self.update_file_list_view()
                event.acceptProposedAction()
            else:
                event.ignore()

        def show_schema_dialog(self, error_msg: str):
            """顯示讓使用者貼上 schema 的對話框"""
            dialog = QDialog(self)
            dialog.setWindowTitle("Schema Error - 請貼上正確的 Schema")
            dialog.setMinimumSize(600, 400)
            layout = QVBoxLayout(dialog)

            label = QLabel(f"處理時發生 Schema 錯誤:\n{error_msg}\n\n請在下方貼上正確的 schema 行：")
            label.setWordWrap(True)
            layout.addWidget(label)

            text_edit = QTextEdit()
            text_edit.setPlaceholderText("在此貼上 schema (例如 log_tag_info 行)...")
            layout.addWidget(text_edit)

            button_box = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel)
            layout.addWidget(button_box)

            button_box.accepted.connect(dialog.accept)
            button_box.rejected.connect(dialog.reject)

            if dialog.exec() == QDialog.Accepted:
                self.worker._schema_text = text_edit.toPlainText()
            else:
                self.worker._schema_text = None

            self.worker._schema_event.set()  # unblock the worker thread

        def closeEvent(self, event):
            if self.thread.isRunning():
                self.worker.interrupt()
                self.worker._schema_event.set()  # unblock worker if waiting
                self.thread.quit()
                self.thread.wait() # 等待線程完全終止
            event.accept()

    app = QApplication(sys.argv)
    window = FileSelectionApp()
    if files:
        for file in files:
            if file not in window.selected_files:
                window.selected_files.append(file)
        window.update_file_list_view()
    window.show()
    sys.exit(app.exec())




def main():
    parser = ArgumentParser(description=__doc__.strip())
    parser.add_argument('-t', '--test', action="store_true", help='Test')
    parser.add_argument('files', nargs="*", action="store", help='Log file')
    args = parser.parse_args()

    if args.test:
        logcsv_test()
        return

    show_window(args.files)


if __name__ == '__main__':
    main()
